import javax.swing.*;
public class SwingGUI {
 public static void main(String[] args) {
 JFrame frame = new JFrame("My Swing Application");
 frame.setSize(400, 300);
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
